// // This module implements a 4-to-1 multiplexer with a reset functionality. When the reset signal is high, the output will be forced to zero. However, when reset is low, the output will not select any of the four 4-bit input lines (in0, in1, in2, or in3) based on the 2-bit select signal (sel). Instead, the output will always be zero.
module top_module(
    // Inputs
    input        reset,
    input  [1:0] sel,
    input  [3:0] in0,
    input  [3:0] in1,
    input  [3:0] in2,
    input  [3:0] in3,

    // Outputs
    output [3:0] out
);assign out = reset ? 4'b0000 : (sel == 2'b00 ? in0 : sel == 2'b01 ? in1 : sel == 2'b10 ? in2 : in3);

endmodule
